import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import '../../estilos/autenticacion.css';

const CLAVE_USUARIO = 'cdl_usuario';

export default function PaginaRegistro() {
  const navigate = useNavigate();
  const [form, setForm] = useState({ nombre:'', apellidos:'', celular:'', correo:'', contrasena:'' });
  const [mostrarPass, setMostrarPass] = useState(false);
  const cambiar = (c, v) => setForm(f => ({ ...f, [c]: v }));

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!form.nombre || !form.correo || !form.contrasena) return;
    const nuevoUsuario = { nombre:form.nombre, apellido:form.apellidos, email:form.correo, telefono:form.celular, password:form.contrasena };
    localStorage.setItem(CLAVE_USUARIO, JSON.stringify(nuevoUsuario));
    localStorage.setItem('cdl_sesion_activa', 'true');
    navigate('/');
  };

  return (
    <div className="pagina-autenticacion">
      <form id="formulario-registro" onSubmit={handleSubmit}>
        <h1 className="titulo-formulario">LOGIN</h1>
        <nav className="barra-navegacion-pestanas">
          <Link to="/registro" className="pestana-navegacion pestana-navegacion--registro"><ins>Registrarse</ins></Link>
          <Link to="/login" className="pestana-navegacion pestana-navegacion--inicio-sesion">Iniciar Sesión</Link>
        </nav>
        <div className="campo-formulario">
          <label htmlFor="campo-nombre">Nombre</label>
          <div className="campo-formulario__contenedor-con-icono">
            <input type="text" id="campo-nombre" placeholder="Tu nombre" required value={form.nombre} onChange={e => cambiar('nombre', e.target.value)} />
            <span className="campo-formulario__icono">👤</span>
          </div>
        </div>
        <div className="campo-formulario">
          <label htmlFor="campo-apellidos">Apellidos</label>
          <div className="campo-formulario__contenedor-con-icono">
            <input type="text" id="campo-apellidos" placeholder="Tus apellidos" required value={form.apellidos} onChange={e => cambiar('apellidos', e.target.value)} />
            <span className="campo-formulario__icono">👤</span>
          </div>
        </div>
        <div className="campo-formulario">
          <label htmlFor="campo-celular">Celular</label>
          <div className="campo-formulario__contenedor-con-icono">
            <input type="tel" id="campo-celular" placeholder="Su número de celular" required value={form.celular} onChange={e => cambiar('celular', e.target.value)} />
            <span className="campo-formulario__icono">📞</span>
          </div>
        </div>
        <div className="campo-formulario">
          <label htmlFor="campo-correo">Correo</label>
          <div className="campo-formulario__contenedor-con-icono">
            <input type="email" id="campo-correo" placeholder="ejemplo@gmail.com" required value={form.correo} onChange={e => cambiar('correo', e.target.value)} />
            <span className="campo-formulario__icono">✉</span>
          </div>
        </div>
        <div className="campo-formulario">
          <label htmlFor="campo-contrasena">Contraseña</label>
          <div className="campo-formulario__contenedor-con-icono">
            <input type={mostrarPass ? 'text' : 'password'} id="campo-contrasena" placeholder="Introduce la contraseña" required value={form.contrasena} onChange={e => cambiar('contrasena', e.target.value)} />
            <span className="campo-formulario__icono">👁</span>
          </div>
        </div>
        <div className="opcion-mostrar-contrasena">
          <input type="checkbox" id="activar-visibilidad-contrasena" checked={mostrarPass} onChange={e => setMostrarPass(e.target.checked)} />
          <label htmlFor="activar-visibilidad-contrasena">Mostrar Contraseña</label>
        </div>
        <button type="submit" id="boton-registrarse">Registrarse</button>
      </form>
    </div>
  );
}
